Hello @valadaptive,

This commit caused a performance regression of the benchmarks we are tracking. Could you please have a look?
The reproducer is as follows (should be compiled w/ -O3 --target=aarch64-unknown-linux-gnu -mcpu=neoverse-v2):

```
__attribute__((aligned(64))) double a[32000];
__attribute__((aligned(64))) double b[32000];
__attribute__((aligned(64))) double c[32000];
__attribute__((aligned(64))) double d[32000];

__attribute__((noinline))
void dummy(double* a, double* b, double* c, double* d, double chksum)
{
    asm volatile("" : : "r"(a), "r"(b), "r"(c), "r"(d), "r"(chksum) : "memory");
}

__attribute__((noinline))
void kernel(int iterations)
{
    double x, chksum;
    int index;
    for (int nl = 0; nl < iterations; nl++) {
        x = a[0];
        index = 0;
        for (int i = 0; i < 32000; ++i) {
            if (a[i] > x) {
                x = a[i];
                index = i;
            }
        }
        chksum = x + (double)index;
        dummy(a, b, c, d, chksum);
    }
}
```

Before the commit this was compiled into a sequence of if statements; after the commit they were replaced with select instructions.
